INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a01', 'attraction', '景點', '奎壁山摩西分海', '湖西', 3, '', '退潮時海中步道浮現，可步行到對面小島，傍晚光線最美。民宿開車10分鐘。記得先查潮汐時間！', '退潮步道、小島', '["#必去","#潮汐","#打卡"]', 1, 23.5919, 119.6725, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a02', 'attraction', '景點', '林投海灘', '湖西', 2, '', '距民宿6分鐘，下午夕陽可以去沙灘走走。旁邊就是及林春咖啡館，適合搭配。', '沙灘、夕陽', '["#沙灘","#夕陽"]', 1, 23.5685, 119.6472, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a03', 'attraction', '景點', '山水沙灘', '湖西', 2, '', '距民宿10分鐘，本島知名沙灘，有許多水上活動業者，可以去體驗看看。', '沙灘、水上活動', '["#沙灘","#水上活動"]', 0, 23.5475, 119.6155, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a04', 'attraction', '景點', '後寮天堂路', '白沙', 3, '', '延伸入海的筆直道路，退潮時海天一色，非常震撼。北環必去。', '入海之路、絕景', '["#北環","#打卡","#必去"]', 0, 23.6354, 119.582, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a05', 'attraction', '景點', '通梁古榕 / 跨海大橋', '白沙', 2, '', '300年古榕盤根錯節，充滿生命力。跨海大橋連接白沙與西嶼，開車過橋本身也是一種體驗。', '古榕樹、跨海大橋', '["#北環","#文化"]', 0, 23.6398, 119.5022, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a06', 'attraction', '景點', '二崁聚落', '西嶼', 2, '', '保存完整的咾咕石古厝聚落，搭配二崁杏仁茶和豆花，是北環半日行程的完美組合。', '咾咕石古厝', '["#北環","#古厝","#文化"]', 0, 23.6001, 119.4546, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a07', 'attraction', '景點', '漁翁島燈塔', '西嶼', 2, '', '台灣最古老的燈塔之一，站在燈塔旁俯瞰整個西嶼海岸，壯觀無比。', '百年燈塔', '["#北環","#燈塔","#打卡"]', 0, 23.5583, 119.4191, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a08', 'attraction', '景點', '內垵遊憩區', '西嶼', 2, '', '清澈海灣，適合玩水戲沙，北環路線的中繼好去處。', '清澈海灣', '["#北環","#沙灘","#玩水"]', 0, 23.57, 119.422, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a09', 'attraction', '景點', '嵵裡沙灘', '馬公', 2, '', '南環必訪的美麗沙灘，水質清澈，相對安靜少人。', '沙灘、清澈海水', '["#南環","#沙灘"]', 0, 23.5368, 119.602, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a10', 'attraction', '景點', '風櫃洞', '馬公', 2, '', '海浪打入天然玄武岩洞穴，聲音猶如天然管風琴。退潮時音效最佳。', '天然海蝕洞穴、濤聲', '["#南環","#自然景觀"]', 0, 23.528, 119.558, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a11', 'attraction', '景點', '吉貝島', '白沙', 3, '', '從赤崁搭船20分鐘，SUP、浮潛、香蕉船一次滿足。澎湖水上活動的天堂。', 'SUP、浮潛、水上活動', '["#離島","#水上活動","#必去"]', 0, 23.6916, 119.5738, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', 'ferry', '{"harborId":"chikan","minutes":20,"note":"赤崁港搭船 20 分鐘"}');
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a12', 'attraction', '景點', '七美島', '七美', 3, '', '從馬公搭船約2小時，澎湖最南端的小島。雙心石滬、燈塔，值得安排一整天。', '雙心石滬、燈塔', '["#離島","#必去"]', 0, 23.2108, 119.4445, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', 'ferry', '{"harborId":"nanhai","minutes":90,"note":"南海遊客中心搭船 90 分鐘（或從馬公機場飛機 15 分鐘）"}');
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a14', 'attraction', '景點', '望安島', '望安', 2, '', '馬公搭船約50分鐘。傳統古厝保存最完整的澎湖離島，天台山可俯瞰全島。綠蠵龜保育區也在這裡，若有機會更可接著搭短程船去旁邊的將軍澳嶼。', '古厝聚落、天台山、綠蠵龜', '["#離島","#古厝","#生態","#南海"]', 0, 23.3677, 119.5077, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', 'ferry', '{"harborId":"nanhai","minutes":50,"note":"南海遊客中心搭船約 50 分鐘"}');
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a15', 'attraction', '景點', '虎井嶼', '馬公', 2, '', '馬公搭船僅20分鐘，卻像走進另一個世界。島上貓咪成群自在漫步，玄武岩石巷靜謐迷人，也是熱門浮潛景點。', '貓島、玄武岩石巷、浮潛', '["#離島","#貓島","#浮潛","#南海"]', 0, 23.5358, 119.5028, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', 'ferry', '{"harborId":"nanhai","minutes":20,"note":"南海遊客中心搭船約 20 分鐘"}');
INSERT OR REPLACE INTO drift_spots (id, type, cat, name, area, rating, price, note, feature, tags, nearby, lat, lng, status, noLoc, displayOrder, createdBy, createdAt, updatedAt, transport, ferry) VALUES ('a13', 'attraction', '景點', '澎湖灣花火節', '馬公', 3, '', '每年約5–8月舉辦。夜晚花火倒映在海面上，是澎湖夏天最大盛事。', '花火節、夜景', '["#活動","#季節限定","#必去"]', 0, 23.5642, 119.5785, 'open', 0, NULL, 'owner', '2026-06-01T15:53:11.509Z', '2026-06-01T15:53:11.509Z', NULL, NULL);
